parameters.inputSchema:
{
	"type": "object",
	"properties": {
		"contractId": {
			"type": "string",
			"description": "Unique identifier for the contract"
		},
		"riskLevel": {
			"type": "string",
			"enum": ["low", "medium", "high", "critical"],
			"description": "Overall risk classification of the contract"
		},
		"riskClauses": {
			"type": "array",
			"items": {
				"type": "object",
				"properties": {
					"clauseText": {
						"type": "string",
						"description": "The text of the risky clause"
					},
					"riskType": {
						"type": "string",
						"description": "Type of risk identified"
					}
				},
				"required": ["clauseText", "riskType"]
			},
			"description": "Array of identified risky clauses"
		},
		"obligations": {
			"type": "array",
			"items": {
				"type": "object",
				"properties": {
					"obligationDescription": {
						"type": "string",
						"description": "Description of the obligation"
					},
					"partyResponsible": {
						"type": "string",
						"description": "Party responsible for fulfilling the obligation"
					}
				},
				"required": ["obligationDescription", "partyResponsible"]
			},
			"description": "Array of contractual obligations"
		},
		"complianceStatus": {
			"type": "string",
			"enum": ["compliant", "non-compliant", "requires-review"],
			"description": "Overall compliance status of the contract"
		},
		"complianceIssues": {
			"type": "array",
			"items": {
				"type": "string"
			},
			"description": "Array of identified compliance issues"
		},
		"regulatoryRequirements": {
			"type": "array",
			"items": {
				"type": "string"
			},
			"description": "Array of applicable regulatory requirements"
		},
		"approvalRequired": {
			"type": "boolean",
			"description": "Whether approval is required for this contract"
		},
		"approvers": {
			"type": "array",
			"items": {
				"type": "string"
			},
			"description": "Array of required approvers"
		},
		"legalSummary": {
			"type": "string",
			"description": "Comprehensive legal summary of the contract"
		},
		"auditNotes": {
			"type": "string",
			"description": "Notes for audit purposes"
		},
		"recommendedActions": {
			"type": "array",
			"items": {
				"type": "string"
			},
			"description": "Array of recommended actions"
		},
		"timestamp": {
			"type": "string",
			"description": "Timestamp of the review"
		}
	},
	"required": ["contractId", "riskLevel", "riskClauses", "obligations", "complianceStatus", "complianceIssues", "regulatoryRequirements", "approvalRequired", "approvers", "legalSummary", "auditNotes", "recommendedActions", "timestamp"]
}
